 using Microsoft.EntityFrameworkCore;

 class BlogContext : DbContext
 {
     public DbSet<Blog> Blogs => Set<Blog>();

     protected override void OnModelCreating(ModelBuilder modelBuilder)
     {
         modelBuilder.Entity<Blog>(entity =>
         {
             // Fix #1 – Discriminator property renamed from "Discriminator" to "$type".
             // Keep old name so existing documents are still recognised.
             entity.HasDiscriminator<string>("Discriminator");

             // Fix #2 – Cosmos "id" no longer includes the discriminator prefix.
             // Preserve the legacy "Blog|{key}" format for existing documents.
             entity.Property(b => b.Id)
                 .HasConversion(
                     key => "Blog|" + key,
                     id  => id.Substring(id.IndexOf('|') + 1));

             // Fix #3 – HasIndex() now throws for the Cosmos provider (was silently ignored).
             // REMOVED: entity.HasIndex(b => b.Name);
         });
     }
 }

 class Blog { public string Id { get; set; } public string Name { get; set; } }

